kw.msg:
Executing JavaScript:
var links = document.querySelectorAll('a.productName');var row = null;for(var i=0;i<links.length;i++){ if(links[i].textContent.trim().toLowerCase().indexOf('HP Roar Mini Wireless Speaker'.toLowerCase())!==-1){ row=links[i].closest('tr'); break; } }if(!row){ row=document.querySelector('a.productName').closest('tr'); }row.dispatchEvent(new MouseEvent('mouseover',{bubbles:true,cancelable:true}));
Without any arguments.

